import React, { useContext, useState } from "react";
import { useShoppingCart } from "../contexts/CartContext";


const Cart = () => {
  const { cartItems, removeItemFromCart, clearCart, totalPrice, updateItemQuantity } = useShoppingCart();

  return (
    <div className="container mx-auto p-6">
      <h2 className="text-2xl font-semibold mb-4">Shopping Cart</h2>
      {cartItems.length > 0 ? (
        <>
          <ul>
            {cartItems.map((item) => (
              <li
                key={item.id}
                className="mb-4 border p-4 rounded flex justify-between items-center"
              >
                <div>
                  <h3 className="text-lg font-semibold">{item.title}</h3>
                  <p>Price: ${item.price}</p>
                  <p>Quantity: {item.quantity}</p>
                </div>
                <div>
                  <div className="flex items-center mt-2">
                    <button
                      onClick={() => updateItemQuantity(item.id, item.quantity - 1)}
                      disabled={item.quantity === 1}
                      className={`px-2 py-1 bg-gray-300 rounded ${item.quantity === 1
                        ? "cursor-not-allowed opacity-50"
                        : "hover:bg-gray-400"
                        }`}
                    >
                      -
                    </button>
                    <span className="font-semibold">{item.quantity}</span>
                    <button
                      onClick={() => updateItemQuantity(item.id, item.quantity + 1)}
                      className="px-2 py-1 bg-blue-500 text-white rounded hover:bg-blue-600"
                    >
                      +
                    </button>
                  </div>
                  <button
                    onClick={() => removeItemFromCart(item.id)}
                    className="bg-red-500 text-white px-4 py-2 rounded hover:bg-red-600"
                  >
                    Remove
                  </button>
                </div>
              </li>
            ))}
          </ul>
          <div className="mt-6 text-right">
            <p className="text-xl font-semibold">Total: ${totalPrice.toFixed(2)}</p>
          </div>
          <button
            type="submit"
            className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700"
          >
            Confirm Order
          </button>
        </>
      ) : (
        <p>Your cart is empty.</p>
      )}
    </div>
  );
};

export default Cart;
